import { useState } from 'react';
import { Reorder, useDragControls } from 'framer-motion';
import { useEffectsStore, EFFECT_HUE, EFFECT_LABEL, EFFECT_DRAG_MIME, type Effect, type EffectKind } from '../../stores/effectsStore';
import { EffectIcon } from '../layout/EffectsSection';
import ChannelEqPanel from './ChannelEqPanel';
import CompressorPanel from './CompressorPanel';
import ReverbPanel from './ReverbPanel';

// Per-track FX chain editor. Sits above the per-clip controls in
// SampleEditorPanel whenever the selected track has at least one effect.
// Drag cards to reorder, click ⊘ to bypass, click × to remove. Controls
// inside each card are placeholders — actual DSP routing comes in a
// follow-up; the chain shape is what matters here so the visual flow
// (drop → reorder → bypass → delete) works end-to-end now.

export default function EffectChainEditor({ laneKey, embedded = false, emptyMessage }: { laneKey: string; embedded?: boolean; emptyMessage?: string }) {
  // Subscribe to byProject so we re-render when other components mutate
  // the chain (drop on the lane, etc.). getChain reads off currentProjectId.
  const byProject = useEffectsStore((s) => s.byProject);
  void byProject;
  const chain = useEffectsStore((s) => s.getChain(laneKey));
  const setOrder = useEffectsStore((s) => s.setOrder);
  const remove = useEffectsStore((s) => s.remove);
  const toggleBypass = useEffectsStore((s) => s.toggleBypass);

  // Append-on-drop handlers used by both the embedded and standalone
  // renders so the user can keep dropping effects after the first one.
  const [railDragOver, setRailDragOver] = useState(false);
  const isEffectDrag = (dt: DataTransfer): boolean => {
    for (const t of Array.from(dt.types)) if (t === EFFECT_DRAG_MIME) return true;
    return false;
  };
  const onRailDragOver = (e: React.DragEvent<HTMLDivElement>) => {
    if (!laneKey || !isEffectDrag(e.dataTransfer)) return;
    e.preventDefault();
    e.dataTransfer.dropEffect = 'copy';
    if (!railDragOver) setRailDragOver(true);
  };
  const onRailDragLeave = () => setRailDragOver(false);
  const onRailDrop = (e: React.DragEvent<HTMLDivElement>) => {
    if (!laneKey || !isEffectDrag(e.dataTransfer)) return;
    e.preventDefault();
    setRailDragOver(false);
    try {
      const raw = e.dataTransfer.getData(EFFECT_DRAG_MIME);
      const payload = JSON.parse(raw) as { kind: EffectKind };
      if (!payload?.kind) return;
      useEffectsStore.getState().add(laneKey, payload.kind);
    } catch { /* malformed payload — ignore */ }
  };
  // Trailing "drop more" slot at the end of the chain rail. Renders
  // a faint dashed box that lights up while dragging, so users see
  // a clear target for adding additional effects beyond the first.
  const TrailingDropSlot = () => (
    <div
      className="shrink-0 self-stretch flex items-center justify-center rounded-xl select-none transition-colors"
      style={{
        width: 110,
        height: 252,
        border: railDragOver ? '2px dashed rgba(168, 85, 247, 0.85)' : '1.5px dashed rgba(255,255,255,0.10)',
        background: railDragOver ? 'rgba(168, 85, 247, 0.12)' : 'rgba(255,255,255,0.02)',
      }}
    >
      <span className={`text-[10.5px] uppercase tracking-wider px-2 text-center leading-tight ${railDragOver ? 'text-white font-semibold' : 'text-white/35 italic'}`}>
        {railDragOver ? 'Drop to add' : 'Drop another EQ or Comp'}
      </span>
    </div>
  );

  if (!laneKey) return null;
  if (!chain || chain.length === 0) {
    // Show a dedicated drop target so the user knows where effects
    // can land. Skip when embedded — the parent owns the layout in
    // that mode and renders its own empty state if it wants one.
    if (embedded) return null;
    return (
      <EmptyChainDropzone
        laneKey={laneKey}
        message={emptyMessage ?? 'Drag EQ or Comp from the sidebar to add effects to this track.'}
      />
    );
  }

  // When embedded, render only the inner chain rail. Caller is
  // responsible for the surrounding card / spacing. Lets the
  // SampleEditorPanel fuse the chain editor with the per-clip
  // controls into a single glass card.
  if (embedded) {
    return (
      <div
        className="shrink-0 px-3 py-3 overflow-x-auto"
        onDragOver={onRailDragOver}
        onDragEnter={onRailDragOver}
        onDragLeave={onRailDragLeave}
        onDrop={onRailDrop}
      >
        <Reorder.Group
          axis="x"
          values={chain.map((e) => e.id)}
          onReorder={(newIds) => setOrder(laneKey, newIds as string[])}
          className="flex gap-2 items-stretch"
          style={{ listStyle: 'none', padding: 0, margin: 0 }}
        >
          {chain.map((fx, idx) => {
            const isLast = idx === chain.length - 1;
            if (fx.kind === 'eq') {
              return (
                <EqChainItem
                  key={fx.id}
                  fx={fx}
                  laneKey={laneKey}
                  isLast={isLast}
                  onClose={() => remove(laneKey, fx.id)}
                />
              );
            }
            if (fx.kind === 'comp') {
              return (
                <CompChainItem
                  key={fx.id}
                  fx={fx}
                  laneKey={laneKey}
                  isLast={isLast}
                  onClose={() => remove(laneKey, fx.id)}
                />
              );
            }
            if (fx.kind === 'reverb') {
              return (
                <ReverbChainItem
                  key={fx.id}
                  fx={fx}
                  laneKey={laneKey}
                  isLast={isLast}
                  onClose={() => remove(laneKey, fx.id)}
                />
              );
            }
            return (
              <ChainCard
                key={fx.id}
                fx={fx}
                isLast={isLast}
                onBypass={() => toggleBypass(laneKey, fx.id)}
                onRemove={() => remove(laneKey, fx.id)}
              />
            );
          })}
        </Reorder.Group>
        <div className="ml-2 inline-flex"><TrailingDropSlot /></div>
      </div>
    );
  }

  return (
    <div
      className="shrink-0 mt-2 rounded-2xl glass flex overflow-hidden"
      onDragOver={onRailDragOver}
      onDragEnter={onRailDragOver}
      onDragLeave={onRailDragLeave}
      onDrop={onRailDrop}
    >
      {/* Chain rail spans the whole panel — no separate identity column. */}
      <div className="flex-1 min-w-0 px-3 py-3 overflow-x-auto flex items-stretch gap-2">
        <Reorder.Group
          axis="x"
          values={chain.map((e) => e.id)}
          onReorder={(newIds) => setOrder(laneKey, newIds as string[])}
          className="flex gap-2 items-stretch"
          style={{ listStyle: 'none', padding: 0, margin: 0 }}
        >
          {chain.map((fx, idx) => {
            const isLast = idx === chain.length - 1;
            // EQ renders the full Channel EQ widget. The panel owns its
            // own bypass + close icons inside the header, so onBypass /
            // onRemove from this scope drive close = remove the effect.
            if (fx.kind === 'eq') {
              // EQ panel is reorderable ONLY by the header strip — the
              // body holds the band-node graph and must stay free.
              // useDragControls lets us hand the start trigger to the
              // header's pointer-down via ChannelEqPanel's prop.
              return (
                <EqChainItem
                  key={fx.id}
                  fx={fx}
                  laneKey={laneKey}
                  isLast={isLast}
                  onClose={() => remove(laneKey, fx.id)}
                />
              );
            }
            if (fx.kind === 'comp') {
              return (
                <CompChainItem
                  key={fx.id}
                  fx={fx}
                  laneKey={laneKey}
                  isLast={isLast}
                  onClose={() => remove(laneKey, fx.id)}
                />
              );
            }
            if (fx.kind === 'reverb') {
              return (
                <ReverbChainItem
                  key={fx.id}
                  fx={fx}
                  laneKey={laneKey}
                  isLast={isLast}
                  onClose={() => remove(laneKey, fx.id)}
                />
              );
            }
            return (
              <ChainCard
                key={fx.id}
                fx={fx}
                isLast={isLast}
                onBypass={() => toggleBypass(laneKey, fx.id)}
                onRemove={() => remove(laneKey, fx.id)}
              />
            );
          })}
        </Reorder.Group>
        <TrailingDropSlot />
      </div>
    </div>
  );
}

// Reorder.Item wrapper for EQ panels. dragListener={false} keeps the
// pointer-down on the body / graph from triggering reorder; the header
// strip inside ChannelEqPanel calls dragControls.start(e) when the
// user grabs it, so reorder is opt-in via that one strip only.
function EqChainItem({ fx, laneKey, isLast, onClose }: {
  fx: Effect;
  laneKey: string;
  isLast: boolean;
  onClose: () => void;
}) {
  const dragControls = useDragControls();
  return (
    <Reorder.Item
      value={fx.id}
      dragListener={false}
      dragControls={dragControls}
      style={{ listStyle: 'none' }}
      whileDrag={{ scale: 1.02, zIndex: 30, boxShadow: '0 8px 24px rgba(0,0,0,0.5)' }}
      className="shrink-0"
    >
      <div className="flex items-stretch gap-1">
        <ChannelEqPanel
          laneKey={laneKey}
          effect={fx}
          onClose={onClose}
          onHeaderPointerDown={(e) => {
            // Hand the active pointer event to framer's drag controller
            // so reorder picks up from this gesture. The native event
            // is what framer's gesture recogniser actually inspects —
            // pass it explicitly so older browsers don't trip on the
            // SyntheticEvent wrapper.
            dragControls.start(e.nativeEvent ?? e);
          }}
        />
        {!isLast && (
          <span className="shrink-0 self-center text-[14px] font-bold text-white/30 px-0.5 select-none">→</span>
        )}
      </div>
    </Reorder.Item>
  );
}

// Same drag-handle pattern as EqChainItem — header grip is the only
// reorder trigger so curve / knob drags inside the body stay free.
function CompChainItem({ fx, laneKey, isLast, onClose }: {
  fx: Effect;
  laneKey: string;
  isLast: boolean;
  onClose: () => void;
}) {
  const dragControls = useDragControls();
  return (
    <Reorder.Item
      value={fx.id}
      dragListener={false}
      dragControls={dragControls}
      style={{ listStyle: 'none' }}
      whileDrag={{ scale: 1.02, zIndex: 30, boxShadow: '0 8px 24px rgba(0,0,0,0.5)' }}
      className="shrink-0"
    >
      <div className="flex items-stretch gap-1">
        <CompressorPanel
          laneKey={laneKey}
          effect={fx}
          onClose={onClose}
          onHeaderPointerDown={(e) => dragControls.start(e.nativeEvent ?? e)}
        />
        {!isLast && (
          <span className="shrink-0 self-center text-[14px] font-bold text-white/30 px-0.5 select-none">→</span>
        )}
      </div>
    </Reorder.Item>
  );
}

